impl MmapManager {
    pub fn new(start_addr: VirtAddr) -> Self {
        let start_vpn = start_addr.ceil();
        let end_vpn = VirtPageNum(start_vpn.0 + MMAP_AREA_SIZE / PAGE_SIZE);
        Self {
            vpn_range: VPNRange::new(start_vpn, end_vpn),
            bit_map: Bitmap::new(end_vpn.0 - start_vpn.0),
        }
    }

    pub fn mmap_alloc(&mut self, start: usize, len: usize) -> Option<(VirtAddr, VirtAddr)> {
        let mmap_start_vpn = self.vpn_range.get_start();
        let pages = (len + PAGE_SIZE - 1) / PAGE_SIZE;
        if start == 0 {
            if let Some(node) = self.bit_map.alloc(pages) {
                let start_vpn = mmap_start_vpn.0 + node;
                let end_vpn = start_vpn + pages;
                log::trace!("start_vpn: {}, end_vpn: {}",start_vpn, end_vpn);
                return Some((VirtPageNum(start_vpn).into(), VirtPageNum(end_vpn).into()));
            }else{
                return None;
            }
        }else{
            let start_vpn = VirtAddr(start).ceil();
            if let Some(_) = self.bit_map.alloc_by_range(start_vpn.0 - mmap_start_vpn.0, pages) {
                let end_vpn = start_vpn.0 + pages;
                return Some((VirtAddr(start), VirtPageNum(end_vpn).into()));
            }else{
                if let Some(node) = self.bit_map.alloc(pages) {
                    let start_vpn = mmap_start_vpn.0 + node;
                    let end_vpn = start_vpn + pages;
                    log::trace!("start_vpn: {}, end_vpn: {}",start_vpn, end_vpn);
                    return Some((VirtPageNum(start_vpn).into(), VirtPageNum(end_vpn).into()));
                }else{
                    return None;
                }
            }
        }
    }

    pub fn mmap_dealloc(&mut self, start: usize, len: usize)  {
        let mmap_start_vpn = self.vpn_range.get_start();
        let pages = (len + PAGE_SIZE - 1) / PAGE_SIZE;
        let start_vpn = VirtAddr(start).ceil();
        self.bit_map.dealloc(start_vpn.0 - mmap_start_vpn.0, pages)
    }

}

