pub const AT_FDCWD: i32 = -100;

pub fn sys_write(fd: usize, buf: *const u8, len: usize) -> isize {
    let token = current_user_token();
    let process = current_process();
    let inner = process.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        log::trace!("sys_write 2001");
        return -1;
    }
    if let Some(file) = &inner.fd_table[fd] {
        if !file.writable() {
            log::trace!("sys_write 2002, fd {}", fd);
            return -1;
        }
        let file = file.clone();
        // release current task TCB manually to avoid multi-borrow
        drop(inner);
        log::trace!("sys_write 2003");
        file.write(&mut UserBuffer::new(translated_byte_buffer(token, buf, len))) as isize
    } else {
        log::trace!("sys_write 2004");
        -1
    }
}

pub fn sys_read(fd: usize, buf: *const u8, len: usize) -> isize {
    let token = current_user_token();
    let process = current_process();
    let inner = process.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return -1;
    }
    if let Some(file) = &inner.fd_table[fd] {
        let file = file.clone();
        if !file.readable() {
            return -1;
        }
        // release current task TCB manually to avoid multi-borrow
        drop(inner);
        file.read(&mut UserBuffer::new(translated_byte_buffer(token, buf, len))) as isize
    } else {
        -1
    }
}

pub fn sys_open(path: *const u8, flags: u32) -> isize {
    let process = current_process();
    let token = current_user_token();
    let path_return = translated_str(token, path);
    let path_own = path_return.to_string();
    log::trace!("sys_open open: {}", path_return);
    if let Some(inode) = open_file(&path_own, OpenFlags::from_bits(flags).unwrap()) {
        let mut inner = process.inner_exclusive_access();
        let fd = inner.alloc_fd();
        inner.fd_table[fd] = Some(inode);
        fd as isize
    } else {
        -1
    }
}

pub fn sys_openat(dirfd: i32, path: *const u8, flags: i32) -> isize {
    let process = current_process();
    let token = current_user_token();
    let path_return = translated_str(token, path);
    let inner = process.inner_exclusive_access();
    // log::info!("sys_openat dirfd: {}, path: {}, flags: {}",dirfd, path_return, flags);
    if dirfd == AT_FDCWD {
        let parent_inode = inner.cwd;
        drop(inner);
        if let Some(inode) = openat(parent_inode, &path_return, flags) {
            log::trace!("sys_openat openat 1111");
            let mut inner = process.inner_exclusive_access();
            let fd = inner.alloc_fd();
            inner.fd_table[fd] = Some(inode);
            log::trace!("sys_openat openat 1112");
            fd as isize
        } else {
            ENOENT
        }
    }else{
        let dirfd = dirfd as usize;
        if dirfd >= inner.fd_table.len() {
            return -1;
        }
        if let Some(file) = &inner.fd_table[dirfd] {
            let file = file.clone();
            if !file.readable() {
                return -1;
            }
            // release current task TCB manually to avoid multi-borrow
            drop(inner);
            let parent_inode = file.getid();
            if let Some(inode) = openat(parent_inode, &path_return, flags) {
                log::trace!("sys_openat openat 2222");
                let mut inner = process.inner_exclusive_access();
                let fd = inner.alloc_fd();
                inner.fd_table[fd] = Some(inode);
                fd as isize
            } else {
                ENOENT
            }
        } else {
            ENFILE
        }
    }
}

pub fn sys_close(fd: usize) -> isize {
    let process = current_process();
    let mut inner = process.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return -1;
    }
    if inner.fd_table[fd].is_none() {
        return -1;
    }
    inner.fd_table[fd].take();
    0
}

pub fn sys_pipe(pipe: *const u8) -> isize {
    let len = core::mem::size_of::<u32>() * 2;
    let process = current_process();
    let token = current_user_token();
    let mut inner = process.inner_exclusive_access();
    let (pipe_read, pipe_write) = make_pipe();
    let read_fd = inner.alloc_fd();//3
    inner.fd_table[read_fd] = Some(pipe_read);
    let write_fd = inner.alloc_fd();//4
    inner.fd_table[write_fd] = Some(pipe_write);
    let data = [read_fd as u32,write_fd as u32];
    // *translated_refmut(token, pipe) = read_fd;
    // *translated_refmut(token, unsafe { pipe.add(1) }) = write_fd;
    let mut user_buffer = UserBuffer::new(translated_byte_buffer(token, pipe, len));
    user_buffer.write_from_slice(to_bytes(&data));
    // log::info!("sys_pipe read_fd:{read_fd},write_fd:{write_fd}");
    0
}

pub fn sys_dup(fd: usize) -> isize {
    let process = current_process();
    let mut inner = process.inner_exclusive_access();
    if inner.fd_table.len() >= MAX_FILE_COUNT {
        log::error!("file full [error in sys_dup]");
        return EMFILE;
    }
    if fd >= inner.fd_table.len() {
        return -1;
    }
    if inner.fd_table[fd].is_none() {
        return -1;
    }
    let new_fd = inner.alloc_fd();
    inner.fd_table[new_fd] = Some(Arc::clone(inner.fd_table[fd].as_ref().unwrap()));
    new_fd as isize
}

