const VIRTIO0: usize = 0x10001000;

const DEVICE_BLOCK_SIZE: usize = 512;

pub struct VirtIOBlock {
    virtio_blk: UPIntrFreeCell<VirtIOBlk<'static, VirtioHal>>,
    condvars: BTreeMap<u16, Condvar>,
}

impl BlockDevice for VirtIOBlock {
    fn read_offset(&self, offset: usize) -> Vec<u8> {
        // log::info!("offset: {}", offset);
        let block_id = offset / DEVICE_BLOCK_SIZE;
        let mut result_buf = vec![0u8; BLOCK_SIZE];
        // log::info!("read offset2");
        let inner_offset = offset % DEVICE_BLOCK_SIZE;
        // log::info!("read offset3");
        if inner_offset == 0 {
            self.read_block(block_id, &mut result_buf);
        } else {
            let mut temp_buf = vec![0u8; BLOCK_SIZE + DEVICE_BLOCK_SIZE];
            self.read_block(block_id, &mut temp_buf);
            result_buf[..BLOCK_SIZE].copy_from_slice(
                &temp_buf[inner_offset..inner_offset + BLOCK_SIZE],);
        }
        // log::info!("read complete");
        result_buf
    }

    fn write_offset(&self, offset: usize, data: &[u8]) {
        let start_block_id = offset / DEVICE_BLOCK_SIZE;
        let write_len = data.len();
        let end_block_id = (offset + write_len - 1) / DEVICE_BLOCK_SIZE;
        let fit_len = (end_block_id - start_block_id + 1) * DEVICE_BLOCK_SIZE;
        let mut temp_buf = vec![0u8; fit_len];
        self.read_block(start_block_id, &mut temp_buf);
        temp_buf[offset % DEVICE_BLOCK_SIZE..offset % DEVICE_BLOCK_SIZE + write_len].copy_from_slice(&data);
        self.write_block(start_block_id, &temp_buf);
    }

    fn handle_irq(&self) {
        self.virtio_blk.exclusive_session(|blk| {
            while let Ok(token) = blk.pop_used() {
                self.condvars.get(&token).unwrap().signal();
            }
        });
    }
}


impl VirtIOBlock {
    pub fn read_block(&self, block_id: usize, buf: &mut [u8]) {
        // log::info!("read block 0");
        let nb = *DEV_NON_BLOCKING_ACCESS.exclusive_access();
        if false {
            // log::info!("read block 1");
            let mut resp = BlkResp::default();
            let task_cx_ptr = self.virtio_blk.exclusive_session(|blk| {
                let token = unsafe { blk.read_block_nb(block_id, buf, &mut resp).unwrap() };
                self.condvars.get(&token).unwrap().wait_no_sched()
            });
            // log::info!("read block 2");
            schedule(task_cx_ptr);
            assert_eq!(
                resp.status(),
                RespStatus::Ok,
                "Error when reading VirtIOBlk"
            );
            // log::info!("read block 5");
        } else {
            // log::info!("read block 3");
            match self.virtio_blk.exclusive_access().read_block(block_id, buf) {
                    Ok(_) => {},
                    Err(e) => {
                        log::trace!("Error when reading VirtIOBlk: {:?}, block_id: {}, buf: {:x?}", e, block_id, buf);
                    },
                };
            // log::info!("read block 4");
        }
    }
    pub fn write_block(&self, block_id: usize, buf: &[u8]) {
        let nb = *DEV_NON_BLOCKING_ACCESS.exclusive_access();
        if false {
            let mut resp = BlkResp::default();
            let task_cx_ptr = self.virtio_blk.exclusive_session(|blk| {
                let token = unsafe { blk.write_block_nb(block_id, buf, &mut resp).unwrap() };
                self.condvars.get(&token).unwrap().wait_no_sched()
            });
            schedule(task_cx_ptr);
            assert_eq!(
                resp.status(),
                RespStatus::Ok,
                "Error when writing VirtIOBlk"
            );
        } else {
            self.virtio_blk
                .exclusive_access()
                .write_block(block_id, buf)
                .expect("Error when writing VirtIOBlk");
        }
    }

}


impl VirtIOBlock {
    pub fn new() -> Self {
        let virtio_blk = unsafe {
            UPIntrFreeCell::new(
                VirtIOBlk::<VirtioHal>::new(&mut *(VIRTIO0 as *mut VirtIOHeader)).unwrap(),//origin in rCore-v3
                // VirtIOBlk::<VirtioHal>::new(&mut *(0x10001000 as *mut VirtIOHeader)).unwrap(), //for mark
            )
        };
        let mut condvars = BTreeMap::new();
        let channels = virtio_blk.exclusive_access().virt_queue_size();
        for i in 0..channels {
            let condvar = Condvar::new();
            condvars.insert(i, condvar);
        }
        Self {
            virtio_blk,
            condvars,
        }
    }
}

