/// It is based on the `std::io::SeekFrom` enum.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SeekFrom {
    /// Sets the offset to the provided number of bytes.
    Start(usize),
    /// Sets the offset to the size of this object plus the specified number of bytes.
    End(isize),
    /// Sets the offset to the current position plus the specified number of bytes.
    Current(isize),
}

pub trait File: Send + Sync {
    fn getid(&self) -> u32;
    fn readable(&self) -> bool;
    fn writable(&self) -> bool;
    fn read<'a>(&self, buf: &'a mut UserBuffer<'a>) -> usize;//YHW:ref
    fn write<'a>(&self, buf: &'a mut UserBuffer<'a>) -> usize;//YHW:ref
    fn hang_up(&self) ->bool; //for ppoll, other module do not need it
    fn r_ready(&self) ->bool { 
        true
    }
    fn w_ready(&self) ->bool { 
        true
    }
    fn ioctl(&self, _request: usize, _argp: usize, _token: usize) -> isize {
        //File::ioctl unsupported, so return ENOTTY(-25)
        ENOTTY  //default
    }
    fn get_inner_refmut(&self)-> Option<UPIntrRefMut<'_, OSInodeInner>> {
        None
    }

    fn seek(&self, pos:SeekFrom) ->isize{
        let inode_num=self.getid();
        let mut meta= match self.get_inner_refmut() {
            None => {
                return -1;
            }
            Some(meta) => {
                meta
            }
        };
        match pos{
            SeekFrom::Current(off)=>{
                log::trace!("[seek] current");
                if off<0 {
                    meta.offset -= off.abs() as usize;
                }else {
                    meta.offset += off.abs() as usize;
                }
            }
            SeekFrom::Start(off)=>{
                log::trace!("[seek] start");
                meta.offset=off;
            }
            SeekFrom::End(off)=>{
                log::trace!("[seek] end");
                let ext4_inode_ref=EXT4.get_inode_ref(inode_num);
                let data_len=ext4_inode_ref.inode.size() as usize;
                if off<0 {
                    meta.offset=data_len-off.abs() as usize;
                }   else {
                    meta.offset=data_len+off as usize;
                }               
            }
        }
        meta.offset as isize
    }
}

