pub fn translated_byte_buffer(token: usize, ptr: *const u8, len: usize) -> Vec<&'static mut [u8]> {
    let page_table = PageTableImpl::from_token(token);
    let mut start = ptr as usize;
    let end = start + len;
    let mut v = Vec::new();
    while start < end {
        let start_va = VirtAddr::from(start);
        let mut vpn = start_va.floor();
        let ppn = page_table.translate(vpn).unwrap().ppn();
        vpn.step();
        let mut end_va: VirtAddr = vpn.into();
        end_va = end_va.min(VirtAddr::from(end));
        if end_va.page_offset() == 0 {
            v.push(&mut ppn.get_bytes_array()[start_va.page_offset()..]);
        } else {
            v.push(&mut ppn.get_bytes_array()[start_va.page_offset()..end_va.page_offset()]);
        }
        start = end_va.into();
    }
    v
}

/// Load a string from other address spaces into kernel space without an end `\0`.
pub fn translated_str(token: usize, ptr: *const u8) -> String {
    let page_table = PageTableImpl::from_token(token);
    let mut string = String::new();
    let mut va = ptr as usize;
    loop {
        let ch: u8 = *(page_table
            .translate_va(VirtAddr::from(va))
            .unwrap()
            .get_mut());
        if ch == 0 {
            break;
        }
        string.push(ch as char);
        va += 1;
    }
    string
}

pub fn translated_ref<T>(token: usize, ptr: *const T) -> &'static T {
    let page_table = PageTableImpl::from_token(token);
    page_table
        .translate_va(VirtAddr::from(ptr as usize))
        .unwrap()
        .get_ref()
}

pub fn translated_refmut<T>(token: usize, ptr: *mut T) -> &'static mut T {
    let page_table = PageTableImpl::from_token(token);
    let va = ptr as usize;
    page_table
        .translate_va(VirtAddr::from(va))
        .unwrap()
        .get_mut()
}

pub struct UserBuffer<'a> {
    pub buffers: Vec<&'a mut [u8]>,
    pub offset: usize,
}

impl<'a> UserBuffer<'a> {
    pub fn new(buffers: Vec<&'a mut [u8]>) -> Self {
        Self { buffers, offset: 0 }
    }
    pub fn len(&self) -> usize {
        let mut total: usize = 0;
        for b in self.buffers.iter() {
            total += b.len();
        }
        total
    }

    //实现批量写
    pub fn write_from_slice(&mut self, data: &[u8]) -> usize { //Vec<&'static mut [u8]> 并不是一段连续内存，需要for循环遍历每个块的大小，&'static mut [u8]长度本身只能运行时确定
        let mut inner_offset = self.offset;
        let mut data_pos = 0;
        let mut total_write = 0;
        let data_len = data.len();
        for buf in self.buffers.iter_mut() {
            if data_pos >= data_len {
                break;
            }
            if inner_offset >= buf.len() {
                inner_offset -= buf.len();
                continue;
            }
            let buf_len_left = buf.len() - inner_offset;
            let write_len = buf_len_left.min(data_len - data_pos);
            buf[inner_offset..inner_offset + write_len].copy_from_slice(&data[data_pos..data_pos + write_len]);
            data_pos += write_len;
            inner_offset = 0;
            total_write += write_len;
        }
        self.offset += total_write;
        total_write
    }
}

impl<'a> IntoIterator for UserBuffer<'a> {
    type Item = *mut u8;
    type IntoIter = UserBufferIterator <'a>;
    fn into_iter(self) -> Self::IntoIter {
        UserBufferIterator {
            buffers: self.buffers,
            current_buffer: 0,
            current_idx: 0,
        }
    }
}

pub struct UserBufferIterator<'a> {
    buffers: Vec<&'a mut [u8]>,
    current_buffer: usize,
    current_idx: usize,
}

impl<'a> Iterator for UserBufferIterator<'a> {
    type Item = *mut u8;
    fn next(&mut self) -> Option<Self::Item> {
        if self.current_buffer >= self.buffers.len() {
            None
        } else {
            let r = &mut self.buffers[self.current_buffer][self.current_idx] as *mut _;
            if self.current_idx + 1 == self.buffers[self.current_buffer].len() {
                self.current_idx = 0;
                self.current_buffer += 1;
            } else {
                self.current_idx += 1;
            }
            Some(r)
        }
    }
}

pub struct UserBufferRefIterator<'a> {
    buffers: &'a mut Vec<&'a mut [u8]>, 
    current_buffer: usize,
    current_idx: usize,
}

impl<'a> Iterator for UserBufferRefIterator<'a> {
    type Item = &'a mut u8;

    fn next(&mut self) -> Option<Self::Item> {
        while self.current_buffer < self.buffers.len() {
            let buffer = &mut self.buffers[self.current_buffer];
            if self.current_idx < buffer.len() {
                // 这里 trick：必须先把 *buffer 的 lifetime 重新借用一次
                let item_ptr: *mut u8 = &mut buffer[self.current_idx];
                self.current_idx += 1;
                // 这里安全，因为：
                // 1. self 持有唯一可变引用（因为 iter_mut() 里必须 &mut self）
                // 2. 同时只有一个 next() 调用在进行
                // 所以可以安全地从 *mut u8 转成 &'a mut u8
                return Some(unsafe { &mut *item_ptr });
            } else {
                self.current_buffer += 1;
                self.current_idx = 0;
            }
        }
        None
    }
}



impl<'a> UserBuffer<'a> {
    pub fn iter_mut(&'a mut self) -> UserBufferRefIterator<'a> {
        UserBufferRefIterator {
            // buffers: self.buffers.as_mut_slice(),
            buffers: &mut self.buffers,
            current_buffer: 0,
            current_idx: 0,
        }
    }
}

