        rv_set_kernel_trap_entry()
    }
    fn decode_trap_type() -> super::TrapType {
        let scause = scause::read();
        let stval = stval::read();
        match scause.cause() {
            Trap::Exception(Exception::UserEnvCall) => super::TrapType::UserEnvCall,
            Trap::Interrupt(Interrupt::SupervisorTimer) => super::TrapType::SupervisorTimer,
            Trap::Interrupt(Interrupt::SupervisorExternal) => super::TrapType::SupervisorExternal,
            Trap::Exception(Exception::IllegalInstruction) => super::TrapType::IllegalInstruction(stval),
            Trap::Exception(Exception::InstructionFault) => super::TrapType::InstructionFault(stval),
            Trap::Exception(Exception::InstructionPageFault) => super::TrapType::InstructionPageFault(stval),
            Trap::Exception(Exception::LoadFault) => super::TrapType::LoadFault(stval),
            Trap::Exception(Exception::StorePageFault) => super::TrapType::StorePageFault(stval),
            Trap::Exception(Exception::LoadPageFault) => super::TrapType::LoadPageFault(stval),
            _ => super::TrapType::IllegalType,
        }
    }
