        self.x[2] = sp;
    }
    fn app_init_ctx(
        entry: usize,
        sp: usize,
        kernel_satp: usize,
        kernel_sp: usize,
        trap_handler: usize,
    ) -> Self {
        let mut sstatus = sstatus::read();
        // set CPU privilege to User after trapping back
        sstatus.set_spp(SPP::User);
        let mut cx = Self {
            x: [0; 32],
            sstatus,
            sepc: entry,
            kernel_satp,
            kernel_sp,
            kernel_ra: 0,
            trap_handler,
            kernel_s: [0; 12],
            kernel_fp: 0,
            kernel_tp: 0,
            user_fx: FloatContext::new(),
            stored: 0,
        };
        cx.set_sp(sp);
        cx
    }
    fn get_sp(&self) -> usize {
        self.x[2]
    }
    fn trap_return() -> ! {
        rv_trap_return();
    }
    fn get_syscall_args(&self) -> [usize; 7] {
        [self.x[10], self.x[11], self.x[12], self.x[13], self.x[14], self.x[15], self.x[16]]
    }
    fn get_syscall_id(&self) -> usize {
        self.x[17]
    }
}

