#[unsafe(no_mangle)]
pub fn main_trap_handler(trap_type: TrapType) {
    {// put these code into a block, to avoid the borrowMutError
        let curr_process=current_process();
        let mut inner =curr_process.inner_exclusive_access();
        inner.update_utime();
        inner.restart_stime();
    }
    // crate::hal::trap::init_trap();
    match trap_type {
        TrapType::UserEnvCall => {
            // jump to next instruction anyway
            let mut cx = current_trap_cx();
            cx.sepc += 4;
            log::trace!("cx.x4 = {:#x}", cx.x[4]);
            crate::hal::instruction::Arch::enable_supervisor_interrupt();
            // trace_sp();
            // get system call return value
            let syscall_id = cx.get_syscall_id();
            let syscall_args = cx.get_syscall_args();
            let result = syscall(syscall_id, syscall_args);
            // cx is changed during sys_exec, so we have to call it again
            cx = current_trap_cx();
            log::trace!("cx.x4 = {:#x}", cx.x[4]);
            cx.x[10] = result as usize;
        }
        TrapType::StorePageFault(val)
        | TrapType::LoadPageFault(val)
        | TrapType::InstructionFault(val)
        | TrapType::InstructionPageFault(val)
        | TrapType::LoadFault(val) => {
            log::error!(
                "[kernel] {:?} in application, bad addr = {:#x}, bad instruction = {:#x}, kernel killed it. sp = {:#x}",
                trap_type,
                val,
                current_trap_cx().sepc,
                current_trap_cx().kernel_sp,
            );
            current_add_signal(SignalFlags::SIGSEGV);
        }
        TrapType::IllegalInstruction(_) => {
            current_add_signal(SignalFlags::SIGILL);
        }
        TrapType::SupervisorTimer => {
            set_next_trigger();
            check_timer();
            // suspend_current_and_run_next();
        }
        TrapType::SupervisorExternal => {
            crate::board::irq_handler();
        }
        TrapType::IllegalType => {
            log::error!(
                "IllegalType trap type {:?}, stval = {:#x}!",
                trap_type,
                crate::hal::instruction::Arch::read_stval() // read stval
            );
        }
    }
    // check signals
    if let Some((errno, msg)) = check_signals_of_current() {
        log::error!("[kernel] {}", msg);
        info!("find errno {} in signal", errno);
        exit_current_and_run_next(errno);
    }
    {// put these code into a block, to avoid the borrowMutError
        let process_return=current_process();
        let mut inner = process_return.inner_exclusive_access();
        inner.update_stime();
        inner.restart_utime();
    }
}

