    new_pid as isize
}



pub fn sys_exec(path: *const u8, mut args: *const usize) -> isize {
    let token = current_user_token();
    let mut path = translated_str(token, path);
    // log::info!("path:{}",path.as_str());

    let mut args_vec: Vec<String> = Vec::new();
    loop {
        let arg_str_ptr = *translated_ref(token, args);
        if arg_str_ptr == 0 {
            break;
        }
        args_vec.push(translated_str(token, arg_str_ptr as *const u8));
        unsafe {
            args = args.add(1);
        }
    }

    if path.ends_with(".sh") {
        args_vec.insert(0, String::from("sh"));
        args_vec.insert(0, String::from("../busybox"));
        path = String::from("../busybox");
    }
    let process= current_process();
    let process_inner=process.inner_exclusive_access();
    let cwd=process_inner.cwd;
    drop(process_inner);
    drop(process);
    log::trace!("exec path {}",path.as_str());
    if path.ends_with("busybox") {
        // log::info!("in");
        let all_data =  BUSYBOX_BIN.to_vec();
        let process = current_process();
        let argc = args_vec.len();
        // log::info!("in 2");
        process.exec(all_data.as_slice(), args_vec, Vec::new());
        // return argc because cx.x[10] will be covered with it later
        // log::info!("exec busybox successfully");
        argc as isize
    }
    else if let Some(app_inode) = openat(cwd, path.as_str(), 0o02) {
        log::trace!("open file successfully");
        let all_data = app_inode.read_all();
        let process = current_process();
        let argc = args_vec.len();
        process.exec(all_data.as_slice(), args_vec, Vec::new());
        // return argc because cx.x[10] will be covered with it later
        argc as isize
    } else {
        log::error!("fail to open file {}", path.as_str());
        -1
    }
}

/// If there is not a child process whose pid is same as given, return -1.
/// Else if there is a child process but it is still running, return -2, and suspend it
pub fn sys_waitpid(pid: isize, exit_code_ptr: *mut i32) -> isize {
    let process = current_process();
    let mut inner = process.inner_exclusive_access();
    inner.get_cstime();
    inner.get_cutime();

    // if exit_code_ptr.is_null(){//if exit_code_ptr is NULL, then return -1
    //     return -1
    // }

    // // find a child process
    // if !inner
    //     .children
    //     .iter()
    //     .any(|p| pid == -1 || pid as usize == p.getpid())
    // {
    //     return -1;
    //     // ---- release current PCB
    // }
    if inner.children.is_empty() {
        log::trace!("[sys_waitpid] no children");
        return -1;
    }

    if pid != -1 && !inner.children.iter().any(|p| p.getpid() == pid as usize) {
        log::trace!("[sys_waitpid] invalid pid: {}", pid);
        return -1;
    }

    let pair = inner.children.iter().enumerate().find(|(_, p)| {
        // ++++ temporarily access child PCB exclusively
        p.inner_exclusive_access().is_zombie && (pid == -1 || pid as usize == p.getpid())
        // ++++ release child PCB
    });
    if let Some((idx, _)) = pair {
        let child = inner.children.remove(idx);
        // confirm that child will be deallocated after being removed from children list
        assert_eq!(Arc::strong_count(&child), 1);
        let found_pid = child.getpid();
        // ++++ temporarily access child PCB exclusively
        let exit_code = child.inner_exclusive_access().exit_code;
        // ++++ release child PCB

        //if exit_code_ptr is NULL, no need to get exit_code
        if !exit_code_ptr.is_null(){ 
            // `exit_code << 8` to match the linux style
            *translated_refmut(inner.memory_set.token(), exit_code_ptr) = exit_code<< 8;// origin:exit_code;
        }
        log::trace!("pid {} successfully wait pid {} exit_code {}",current_process().getpid(), found_pid, exit_code);
        found_pid as isize
    } else {
        -2
    }// ---- release current PCB automatically
}

pub fn sys_wait4(pid: isize, exit_code_ptr: *mut i32,options :isize,_rusage:isize) -> isize {
    log::trace!("options:{}",options);
    let pid1 = current_process().getpid();
    if options == 0 {//block
        loop {
            log::trace!("parent pid {} waiting pid {} exit_code_ptr {:?} options {}",pid1, pid, exit_code_ptr, options);
            match sys_waitpid(pid, exit_code_ptr) {
                -2 => {
                    sys_yield();
                }
                // -1 or a real pid
                exit_pid => 
                {
                    return exit_pid;
                }
            }
        }
    }else {//options==1, not block
        let exit_pid=sys_waitpid(pid, exit_code_ptr);
        exit_pid
    }
}

