pub fn sys_sbrk(offset: isize) -> isize{
    let program_break = current_task().unwrap().process.upgrade().unwrap().get_program_break();
    match offset {
        0 => {program_break as isize},
        x => {
            assert!(x + offset > 0);
            if current_task().unwrap().process.upgrade().unwrap().brk((x + offset) as usize) == 0 {
                program_break as isize
            }else{
                -1
            }
        },
    }
}

pub fn sys_mmap(start: usize, len: usize, _prot: i32, flags: MmapFlags, fd: usize, offset: usize) -> isize {
    // log::info!("mmap syscall start_required: {}, len_required: {:#x}, prot: {}, flags: {:?}, fd: {}, offset: {}", start, len, _prot, flags, fd, offset);
    let token = current_user_token();
    let process = current_process();
    let mut inner = process.inner_exclusive_access();
    if flags.contains(MmapFlags::MAP_ANONYMOUS) {
        // 支持 MAP_ANONYMOUS | MAP_PRIVATE (常见) 或者单独 MAP_ANONYMOUS
        let addr = inner.memory_set.mmap(start, len) as *const u8;
        // log::info!("mmap anonymous addr: {:p}", addr);
        drop(inner);
        return addr as isize;
    } else if flags.contains(MmapFlags::MAP_PRIVATE) || flags.contains(MmapFlags::MAP_SHARED) || flags.is_empty(){
        // 文件私有映射分支
        // 支持只设定了 MAP_PRIVATE的情况（如内存映射文件、快照）
        if fd >= inner.fd_table.len() {
            log::error!("Illegel fd: {}", fd);
            return -1;
        }
        if let Some(file) = &inner.fd_table[fd] {
            let file = file.clone();
            if !file.readable() {
                log::error!("Irreadable fd: {}", fd);
                return -1;
            }
            // release current task TCB manually to avoid multi-borrow
            let inode_num = file.getid();
            let inode = Inode::new(inode_num);
            let addr = inner.memory_set.mmap(start, len) as *const u8;
            log::trace!("addr: {:p}", addr);
            drop(inner);
            let mut temp_buf = vec![0u8; len];
            let result = inode.read_at(offset, &mut temp_buf);
            if result != len {
                log::error!("3");
                return -1;
            }
            let mut user_buffer = UserBuffer::new(translated_byte_buffer(token, addr, len));
            match user_buffer.write_from_slice(&mut temp_buf) {
                n if n == len => addr as isize,
                _ => -1,
            }
        } else {
            log::error!("4");
            -1
        }
    } else {
        // 其它情况：比如没有支持的 flag，或者 flag 一片空/奇怪的组合
        log::warn!("mmap flags not supported: {}", flags.bits());
        -1
    }
}

