//zsq_socket
// 创建套接字
pub fn sys_socket(domain: u32, typ: u32, protocol: u32) -> isize {
    // 仅支持 IPv4
    if domain != AF_INET {
        return -1;
    }

    // 仅支持 TCP 和 UDP
     match (typ, protocol) {
        (SOCK_STREAM, IPPROTO_TCP) => create_tcp_socket(),
        (SOCK_DGRAM, IPPROTO_UDP) => create_udp_socket(),
        _ => {
            -1
        }
    }
}

// 创建 TCP 套接字
fn create_tcp_socket() -> isize {
    let process = current_process();
    let mut inner = process.inner_exclusive_access();

    // 分配文件描述符
    let fd = inner.alloc_fd();

    // 创建新的 TCP Socket 实例
    let socket = Socket {
        raddr: IPv4::new(0, 0, 0, 0),    // 远程地址（初始化为0）
        lport: 0,                        // 本地端口（将在 bind 或 connect 时分配）
        rport: 0,                        // 远程端口（初始化为0）
        buffers: VecDeque::new(),        // 数据缓冲区
        seq: 1,                          // 初始序列号（从1开始符合TCP规范）
        ack: 0,                          // 初始确认号
    };

    // 添加到 Socket 表
    match add_socket(socket.raddr, socket.lport, socket.rport) {
        Some(socket_index) => {
            // 设置初始序列号和确认号
            set_s_a_by_index(socket_index, socket.seq, socket.ack);
            /*if let Err(e) = set_s_a_by_index(socket_index, socket.seq, socket.ack) {
                // 回滚：移除已添加的 socket
                remove_socket(socket_index);
                return -1;
            }*/

            // 创建 PortFd 并关联到 socket_index
            let port_fd = PortFd::new(socket_index);
            inner.fd_table[fd] = Some(Arc::new(port_fd));

            fd as isize
        }
        None => {
            -1
        }
    }
}

// 创建 UDP 套接字
fn create_udp_socket() -> isize {
    let process = current_process();
    let mut inner = process.inner_exclusive_access();

    // 分配文件描述符
    let fd = inner.alloc_fd();

    // 创建 UDP 节点
    // 初始状态：本地地址和端口暂时为 1024，将在 bind 或 connect 时分配
    let udp_node = match UDP::new(
        IPv4::new(0, 0, 0, 0), // 远程地址（初始化为0）
        1024,                     // 本地端口（将在 bind 时分配）
        0,                     // 远程端口（初始化为0）
    ) {
        udp => udp, // UDP::new 目前没有错误处理，直接使用结果
    };

    // 将 UDP 节点添加到文件描述符表
    inner.fd_table[fd] = Some(Arc::new(udp_node));

    fd as isize
}

// just support udp
pub fn sys_connect(raddr: u32, lport: u16, rport: u16) -> isize {
    let process = current_process();
    let mut inner = process.inner_exclusive_access();
    let fd = inner.alloc_fd();
    let udp_node = UDP::new(IPv4::from_u32(raddr), lport, rport);
    inner.fd_table[fd] = Some(Arc::new(udp_node));
    fd as isize
}

// listen a port
pub fn sys_listen(port: u16) -> isize {
    match listen(port) {
        Some(port_index) => {
            let process = current_process();
            let mut inner = process.inner_exclusive_access();
            let fd = inner.alloc_fd();
            let port_fd = PortFd::new(port_index);
            inner.fd_table[fd] = Some(Arc::new(port_fd));

            // NOTICE: this return the port index, not the fd
            port_index as isize
        }
        None => -1,
    }
}

// accept a tcp connection
pub fn sys_accept(port_index: usize) -> isize {
    println!("accepting port {}", port_index);

    let task = current_task().unwrap();
    accept(port_index, task);
    // block_current_and_run_next();

    // NOTICE: There does not have interrupt handler, just call it munually.
    loop {
        net_interrupt_handler();

        if !port_acceptable(port_index) {
            break;
        }
    }

    let cx = current_trap_cx();
    cx.x[10] as isize
}

use crate::sync::{Condvar, Mutex, MutexBlocking, MutexSpin, Semaphore};
use crate::task::{block_current_and_run_next, current_process, current_task,current_user_token};
use crate::mm::{translated_refmut};
use crate::timer::{add_timer, get_time_ms,TimeSpec};
use alloc::sync::Arc;

pub fn sys_sleep(ms: usize) -> isize {
    let expire_ms = get_time_ms() + ms;
    let task = current_task().unwrap();
    add_timer(expire_ms, task);
    block_current_and_run_next();
    0
}

pub fn sys_nanosleep(
    req: *mut TimeSpec, //the require time to sleep
    rem: *mut TimeSpec  //if be interrupted, record the remain time to sleep
)->isize{
    let token = current_user_token();
    let req_ptr = translated_refmut(token, req);
    let rem_ptr = translated_refmut(token, rem);

    let expire_ms = get_time_ms() + (*req_ptr).to_ms();
    let task = current_task().unwrap();
    add_timer(expire_ms, task);
    block_current_and_run_next();
    (*rem_ptr).tv_sec=0;
    (*rem_ptr).tv_nsec=0;
    0
}

pub fn sys_mutex_create(blocking: bool) -> isize {
    let process = current_process();
    let mutex: Option<Arc<dyn Mutex>> = if !blocking {
        Some(Arc::new(MutexSpin::new()))
    } else {
        Some(Arc::new(MutexBlocking::new()))
    };
    let mut process_inner = process.inner_exclusive_access();
    if let Some(id) = process_inner
        .mutex_list
        .iter()
        .enumerate()
        .find(|(_, item)| item.is_none())
        .map(|(id, _)| id)
    {
        process_inner.mutex_list[id] = mutex;
        id as isize
    } else {
        process_inner.mutex_list.push(mutex);
        process_inner.mutex_list.len() as isize - 1
    }
}

pub fn sys_mutex_lock(mutex_id: usize) -> isize {
    let process = current_process();
    let process_inner = process.inner_exclusive_access();
    let mutex = Arc::clone(process_inner.mutex_list[mutex_id].as_ref().unwrap());
    drop(process_inner);
    drop(process);
    mutex.lock();
    0
}

pub fn sys_mutex_unlock(mutex_id: usize) -> isize {
    let process = current_process();
    let process_inner = process.inner_exclusive_access();
    let mutex = Arc::clone(process_inner.mutex_list[mutex_id].as_ref().unwrap());
    drop(process_inner);
    drop(process);
    mutex.unlock();
    0
}

pub fn sys_semaphore_create(res_count: usize) -> isize {
    let process = current_process();
    let mut process_inner = process.inner_exclusive_access();
    let id = if let Some(id) = process_inner
        .semaphore_list
        .iter()
        .enumerate()
        .find(|(_, item)| item.is_none())
        .map(|(id, _)| id)
    {
        process_inner.semaphore_list[id] = Some(Arc::new(Semaphore::new(res_count)));
        id
    } else {
        process_inner
            .semaphore_list
            .push(Some(Arc::new(Semaphore::new(res_count))));
        process_inner.semaphore_list.len() - 1
    };
    id as isize
}

pub fn sys_semaphore_up(sem_id: usize) -> isize {
    let process = current_process();
    let process_inner = process.inner_exclusive_access();
    let sem = Arc::clone(process_inner.semaphore_list[sem_id].as_ref().unwrap());
    drop(process_inner);
    sem.up();
    0
}

pub fn sys_semaphore_down(sem_id: usize) -> isize {
    let process = current_process();
    let process_inner = process.inner_exclusive_access();
    let sem = Arc::clone(process_inner.semaphore_list[sem_id].as_ref().unwrap());
    drop(process_inner);
    sem.down();
    0
}

pub fn sys_condvar_create() -> isize {
    let process = current_process();
    let mut process_inner = process.inner_exclusive_access();
    let id = if let Some(id) = process_inner
        .condvar_list
        .iter()
        .enumerate()
        .find(|(_, item)| item.is_none())
        .map(|(id, _)| id)
    {
        process_inner.condvar_list[id] = Some(Arc::new(Condvar::new()));
        id
    } else {
        process_inner
            .condvar_list
            .push(Some(Arc::new(Condvar::new())));
        process_inner.condvar_list.len() - 1
    };
    id as isize
}

pub fn sys_condvar_signal(condvar_id: usize) -> isize {
    let process = current_process();
    let process_inner = process.inner_exclusive_access();
    let condvar = Arc::clone(process_inner.condvar_list[condvar_id].as_ref().unwrap());
    drop(process_inner);
    condvar.signal();
    0
}

pub fn sys_condvar_wait(condvar_id: usize, mutex_id: usize) -> isize {
    let process = current_process();
    let process_inner = process.inner_exclusive_access();
    let condvar = Arc::clone(process_inner.condvar_list[condvar_id].as_ref().unwrap());
    let mutex = Arc::clone(process_inner.mutex_list[mutex_id].as_ref().unwrap());
    drop(process_inner);
    condvar.wait_with_mutex(mutex);
    0
}

use crate::drivers::GPU_DEVICE;
use crate::mm::{MapArea, MapPermission, MapType, PhysAddr, VirtAddr};
use crate::task::current_process;

const FB_VADDR: usize = 0x10000000;

pub fn sys_framebuffer() -> isize {
    let fb = GPU_DEVICE.get_framebuffer();
    let len = fb.len();
    // println!("[kernel] FrameBuffer: addr 0x{:X}, len {}", fb.as_ptr() as usize , len);
    let fb_start_pa = PhysAddr::from(fb.as_ptr() as usize);
    assert!(fb_start_pa.aligned());
    let fb_start_ppn = fb_start_pa.floor();
    let fb_start_vpn = VirtAddr::from(FB_VADDR).floor();
    let pn_offset = fb_start_ppn.0 as isize - fb_start_vpn.0 as isize;

    let current_process = current_process();
    let mut inner = current_process.inner_exclusive_access();
    inner.memory_set.push(
        MapArea::new(
            (FB_VADDR as usize).into(),
            (FB_VADDR + len as usize).into(),
            MapType::Linear(pn_offset),
            MapPermission::R | MapPermission::W | MapPermission::U,
        ),
        None,
    );
    FB_VADDR as isize
}

pub fn sys_framebuffer_flush() -> isize {
    GPU_DEVICE.flush();
    0
}
