pub fn write_procinfo_bare() {
    write_proc_global(&ProcInfo::default());
    // write_proc_pid(&ProcInfo::default(), 0);
}

pub fn write_proc_global(proc_info: &ProcInfo) {
    // 遍历所有全局文件
    let dir_inode = match EXT4.ext4_dir_mk_at(2, "proc") {
        Ok(inode_num) => inode_num,
        Err(e) => {
            log::error!("Failed to create /proc: {:?}", e);
            return;
        }
    };

    let files = [
        ("cpuinfo", proc_info.cpuinfo.to_string()),
        ("meminfo", proc_info.meminfo.to_string()),
        ("uptime", proc_info.uptime.to_string()),
        ("version", proc_info.version.to_string()),
        ("stat", proc_info.stat.to_string()),
        ("loadavg", proc_info.loadavg.to_string()),
        ("filesystems", proc_info.filesystems.to_string()),
        ("mounts", proc_info.mounts.to_string()),
    ];

    for (filename, content) in files.iter() {
        let mut parent_inode_num = dir_inode; 
        let inode_num = EXT4
            .generic_open(
                filename,
                &mut parent_inode_num,
                true,
                InodeFileType::S_IFREG.bits(),
                &mut 0,
            )
            .unwrap();
        let inode = Inode::new(inode_num);
        inode.write_at(0, content.as_bytes());
    };
    log::info!("dirents dirinode {}", dir_inode);
    let inode = Inode::new(dir_inode);
    inode.get_dirents();
    log::info!("####################");
}

#[allow(unused)]
pub fn write_proc_pid(proc_info: &ProcInfo, pid: usize) {
    // 构造 /proc/<pid> 目录
    let path = format!("/proc/{}", pid);
    let mut parent_inode_num = ROOT_INODE_NUM;
    let dir_inode = EXT4
        .generic_open(
            &path,
            &mut parent_inode_num,
            true,
            InodeFileType::S_IFDIR.bits(),
            &mut 0,
        )
        .unwrap();

    // 你可以只写与该 pid 有关的文件，比如 stat、status 等
    // 这里只举例 stat
    let mut parent_inode_num = dir_inode;
    let inode_num = EXT4
        .generic_open(
            "stat",
            &mut parent_inode_num,
            true,
            InodeFileType::S_IFREG.bits(),
            &mut 0,
        )
        .unwrap();
    let inode = Inode::new(inode_num);
    inode.write_at(0, proc_info.stat.to_string().as_bytes());

    // 若后续要添加 cmdline/status 之类，可以继续在此处扩展
}


