pub fn device_init() {
    for intr_src_id in 1..132 {
        IRQ_CTRL.enable_irq(intr_src_id);
    }
    Arch::enable_supervisor_interrupt();
}

pub fn irq_handler() {
    let intr_src_id = IRQ_CTRL.claim_irq().unwrap();
    for _ in 0..10 {
        crate::print!("");
    }
    match intr_src_id {
        5 => KEYBOARD_DEVICE.handle_irq(),
        6 => MOUSE_DEVICE.handle_irq(),
        1 => BLOCK_DEVICE.handle_irq(),
        10 => UART.handle_irq(),
        _ => log::error!("unsupported IRQ {}", intr_src_id),
    }
    IRQ_CTRL.complete_irq(intr_src_id);
}

